-- Migration 027: Create all missing tables (no FK constraints to avoid dependency failures)

IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME='Associations')
    CREATE TABLE Associations (Id INT PRIMARY KEY IDENTITY(1,1), AssociationName NVARCHAR(255) NOT NULL DEFAULT '', AdminId INT NOT NULL DEFAULT 0, LogoUrl NVARCHAR(500) NULL, ThemeColor NVARCHAR(7) NOT NULL DEFAULT '#3B82F6', Slug NVARCHAR(100) NOT NULL DEFAULT '', Address NVARCHAR(500) NULL, Phone NVARCHAR(20) NULL, Email NVARCHAR(255) NULL, CreatedAt DATETIME2 NOT NULL DEFAULT GETUTCDATE(), IsActive BIT NOT NULL DEFAULT 1, IsDeleted BIT NOT NULL DEFAULT 1);

IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME='Users')
    CREATE TABLE Users (Id INT PRIMARY KEY IDENTITY(1,1), Username NVARCHAR(100) NOT NULL DEFAULT '', PasswordHash NVARCHAR(MAX) NOT NULL DEFAULT '', FullName NVARCHAR(200) NOT NULL DEFAULT '', Role NVARCHAR(50) NOT NULL DEFAULT 'staff', AssociationId INT NULL, PropertyId INT NULL, BuildingId INT NULL, UnitId INT NULL, Phone NVARCHAR(20) NULL, Address NVARCHAR(500) NULL, ProfilePicture NVARCHAR(500) NULL, IsActive BIT NOT NULL DEFAULT 1, TermsStatus BIT NOT NULL DEFAULT 0, LastLoginAt DATETIME2 NULL, CreatedAt DATETIME2 NOT NULL DEFAULT GETUTCDATE(), IsDeleted BIT NOT NULL DEFAULT 1);

IF NOT EXISTS (SELECT 1 FROM sys.indexes WHERE name='IX_Users_Username' AND object_id=OBJECT_ID('Users'))
    CREATE UNIQUE INDEX IX_Users_Username ON Users(Username);

IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME='Roles')
    CREATE TABLE Roles (Id INT PRIMARY KEY IDENTITY(1,1), RoleName NVARCHAR(100) NOT NULL DEFAULT '', RoleType NVARCHAR(50) NOT NULL DEFAULT '', PermissionLevel INT NOT NULL DEFAULT 0, CanCreateUsers BIT NOT NULL DEFAULT 0, CanAssignComplaints BIT NOT NULL DEFAULT 0, CanApproveWorkOrders BIT NOT NULL DEFAULT 0, CanViewFinancials BIT NOT NULL DEFAULT 0, PermissionsJson NVARCHAR(MAX) NULL, IsDeleted BIT NOT NULL DEFAULT 1);

IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME='Properties')
    CREATE TABLE Properties (Id INT PRIMARY KEY IDENTITY(1,1), AssociationId INT NOT NULL DEFAULT 0, PropertyName NVARCHAR(255) NOT NULL DEFAULT '', Address NVARCHAR(500) NULL, TotalUnits INT NOT NULL DEFAULT 0, PropertyType NVARCHAR(20) NOT NULL DEFAULT 'apartment', TowerName NVARCHAR(100) NULL, FloorNo NVARCHAR(20) NULL, DoorNo NVARCHAR(20) NULL, ContactName NVARCHAR(100) NULL, ContactMobile NVARCHAR(20) NULL, CommonAreas NVARCHAR(500) NULL, CreatedAt DATETIME2 NOT NULL DEFAULT GETUTCDATE(), IsDeleted BIT NOT NULL DEFAULT 1);

IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME='Properties' AND COLUMN_NAME='PropertyType') ALTER TABLE Properties ADD PropertyType NVARCHAR(20) NOT NULL DEFAULT 'apartment';
IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME='Properties' AND COLUMN_NAME='TowerName') ALTER TABLE Properties ADD TowerName NVARCHAR(100) NULL;
IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME='Properties' AND COLUMN_NAME='FloorNo') ALTER TABLE Properties ADD FloorNo NVARCHAR(20) NULL;
IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME='Properties' AND COLUMN_NAME='DoorNo') ALTER TABLE Properties ADD DoorNo NVARCHAR(20) NULL;
IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME='Properties' AND COLUMN_NAME='ContactName') ALTER TABLE Properties ADD ContactName NVARCHAR(100) NULL;
IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME='Properties' AND COLUMN_NAME='ContactMobile') ALTER TABLE Properties ADD ContactMobile NVARCHAR(20) NULL;
IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME='Properties' AND COLUMN_NAME='CommonAreas') ALTER TABLE Properties ADD CommonAreas NVARCHAR(500) NULL;
IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME='Properties' AND COLUMN_NAME='IsDeleted') ALTER TABLE Properties ADD IsDeleted BIT NOT NULL DEFAULT 1;
IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME='Properties' AND COLUMN_NAME='TotalUnits') ALTER TABLE Properties ADD TotalUnits INT NOT NULL DEFAULT 0;

IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME='Buildings')
    CREATE TABLE Buildings (Id INT PRIMARY KEY IDENTITY(1,1), PropertyId INT NOT NULL DEFAULT 0, BuildingName NVARCHAR(100) NOT NULL DEFAULT '', Floors INT NOT NULL DEFAULT 0, CreatedAt DATETIME2 NOT NULL DEFAULT GETUTCDATE(), IsDeleted BIT NOT NULL DEFAULT 1);

IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME='Units')
    CREATE TABLE Units (Id INT PRIMARY KEY IDENTITY(1,1), BuildingId INT NOT NULL DEFAULT 0, UnitNumber NVARCHAR(50) NOT NULL DEFAULT '', FloorNumber INT NOT NULL DEFAULT 0, Area DECIMAL(10,2) NOT NULL DEFAULT 0, ResidentId INT NULL, IsOccupied BIT NOT NULL DEFAULT 0, CreatedAt DATETIME2 NOT NULL DEFAULT GETUTCDATE(), IsDeleted BIT NOT NULL DEFAULT 1);

IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME='Notifications')
    CREATE TABLE Notifications (Id INT PRIMARY KEY IDENTITY(1,1), UserId INT NOT NULL DEFAULT 0, Title NVARCHAR(255) NULL, Message NVARCHAR(MAX) NULL, Type NVARCHAR(50) NULL, ReferenceId INT NOT NULL DEFAULT 0, IsRead BIT NOT NULL DEFAULT 0, CreatedAt DATETIME2 NOT NULL DEFAULT GETUTCDATE(), IsDeleted BIT NOT NULL DEFAULT 1);

IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME='Notifications' AND COLUMN_NAME='IsDeleted') ALTER TABLE Notifications ADD IsDeleted BIT NOT NULL DEFAULT 1;

IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME='AuditLogs')
    CREATE TABLE AuditLogs (Id INT PRIMARY KEY IDENTITY(1,1), UserId INT NOT NULL DEFAULT 0, AssociationId INT NOT NULL DEFAULT 0, Action NVARCHAR(100) NOT NULL DEFAULT '', Module NVARCHAR(50) NOT NULL DEFAULT '', RecordId INT NULL, OldValue NVARCHAR(MAX) NULL, NewValue NVARCHAR(MAX) NULL, IPAddress NVARCHAR(50) NULL, UserAgent NVARCHAR(255) NULL, Timestamp DATETIME2 NOT NULL DEFAULT GETUTCDATE(), IsDeleted BIT NOT NULL DEFAULT 1);

IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME='ComplaintCategories')
    CREATE TABLE ComplaintCategories (Id INT PRIMARY KEY IDENTITY(1,1), AssociationId INT NOT NULL DEFAULT 0, CategoryName NVARCHAR(100) NOT NULL DEFAULT '', Department NVARCHAR(100) NULL, EstimatedTime INT NOT NULL DEFAULT 0, IsActive BIT NOT NULL DEFAULT 1, CreatedAt DATETIME2 NOT NULL DEFAULT GETUTCDATE(), IsDeleted BIT NOT NULL DEFAULT 1);

IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME='SubCategories')
    CREATE TABLE SubCategories (Id INT PRIMARY KEY IDENTITY(1,1), CategoryId INT NOT NULL DEFAULT 0, SubCategoryName NVARCHAR(100) NOT NULL DEFAULT '', Description NVARCHAR(500) NULL, IsActive BIT NOT NULL DEFAULT 1, CreatedAt DATETIME2 NOT NULL DEFAULT GETUTCDATE(), IsDeleted BIT NOT NULL DEFAULT 1);

IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME='Products')
    CREATE TABLE Products (Id INT PRIMARY KEY IDENTITY(1,1), CategoryId INT NOT NULL DEFAULT 0, SubCategoryId INT NULL, ProductName NVARCHAR(255) NOT NULL DEFAULT '', Price DECIMAL(18,2) NOT NULL DEFAULT 0, Description NVARCHAR(MAX) NULL, ImageUrl NVARCHAR(500) NULL, IsActive BIT NOT NULL DEFAULT 1, CreatedAt DATETIME2 NOT NULL DEFAULT GETUTCDATE(), IsDeleted BIT NOT NULL DEFAULT 1);

IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME='Complaints')
    CREATE TABLE Complaints (Id INT PRIMARY KEY IDENTITY(1,1), ComplaintNumber NVARCHAR(50) NOT NULL DEFAULT '', ResidentId INT NOT NULL DEFAULT 0, UnitId INT NULL, CategoryId INT NULL, Title NVARCHAR(255) NOT NULL DEFAULT '', Description NVARCHAR(MAX) NULL, Priority NVARCHAR(20) NOT NULL DEFAULT 'Medium', Status NVARCHAR(50) NOT NULL DEFAULT 'Open', AssignedTo INT NULL, AssignedBy INT NULL, AssignedAt DATETIME2 NULL, Resolution NVARCHAR(MAX) NULL, ResolutionNotes NVARCHAR(MAX) NULL, Rating INT NULL, Feedback NVARCHAR(MAX) NULL, CreatedAt DATETIME2 NOT NULL DEFAULT GETUTCDATE(), ResolvedAt DATETIME2 NULL, ClosedAt DATETIME2 NULL, IsDeleted BIT NOT NULL DEFAULT 1);

IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME='ComplaintAttachments')
    CREATE TABLE ComplaintAttachments (Id INT PRIMARY KEY IDENTITY(1,1), ComplaintId INT NOT NULL DEFAULT 0, FileName NVARCHAR(255) NULL, FilePath NVARCHAR(500) NULL, FileType NVARCHAR(50) NULL, UploadedBy INT NOT NULL DEFAULT 0, UploadedAt DATETIME2 NOT NULL DEFAULT GETUTCDATE(), IsDeleted BIT NOT NULL DEFAULT 1);

IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME='WorkOrders')
    CREATE TABLE WorkOrders (Id INT PRIMARY KEY IDENTITY(1,1), WorkOrderNumber NVARCHAR(50) NOT NULL DEFAULT '', ComplaintId INT NOT NULL DEFAULT 0, VendorId INT NOT NULL DEFAULT 0, Description NVARCHAR(MAX) NULL, EstimatedCost DECIMAL(18,2) NULL, ActualCost DECIMAL(18,2) NULL, Status NVARCHAR(50) NOT NULL DEFAULT 'Pending', ApprovedBy INT NULL, ApprovedAt DATETIME2 NULL, CompletedAt DATETIME2 NULL, CreatedAt DATETIME2 NOT NULL DEFAULT GETUTCDATE(), WorkTitle NVARCHAR(255) NULL, IsDeleted BIT NOT NULL DEFAULT 1);

IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME='Bills')
    CREATE TABLE Bills (Id INT PRIMARY KEY IDENTITY(1,1), UnitId INT NOT NULL DEFAULT 0, BillNumber NVARCHAR(50) NOT NULL DEFAULT '', BillType NVARCHAR(50) NULL, Amount DECIMAL(18,2) NOT NULL DEFAULT 0, Tax DECIMAL(18,2) NOT NULL DEFAULT 0, TotalAmount DECIMAL(18,2) NOT NULL DEFAULT 0, DueDate DATETIME2 NOT NULL DEFAULT GETUTCDATE(), Status NVARCHAR(50) NOT NULL DEFAULT 'Pending', PaidAt DATETIME2 NULL, PaymentReference NVARCHAR(100) NULL, CreatedAt DATETIME2 NOT NULL DEFAULT GETUTCDATE(), IsDeleted BIT NOT NULL DEFAULT 1);

IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME='Departments')
    CREATE TABLE Departments (Id INT PRIMARY KEY IDENTITY(1,1), DepartmentName NVARCHAR(100) NOT NULL DEFAULT '', AssociationId INT NOT NULL DEFAULT 0, CreatedAt DATETIME2 NOT NULL DEFAULT GETUTCDATE());

IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME='WorkCategories')
    CREATE TABLE WorkCategories (Id INT PRIMARY KEY IDENTITY(1,1), WorkCode NVARCHAR(50) NOT NULL DEFAULT '', WorkTitle NVARCHAR(255) NOT NULL DEFAULT '', WorkType NVARCHAR(50) NOT NULL DEFAULT 'Standard', IsActive BIT NOT NULL DEFAULT 1, CreatedAt DATETIME2 NOT NULL DEFAULT GETUTCDATE());

IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME='WorkAllocations')
    CREATE TABLE WorkAllocations (Id INT PRIMARY KEY IDENTITY(1,1), Title NVARCHAR(255) NOT NULL DEFAULT '', Description NVARCHAR(MAX) NULL, WorkId INT NOT NULL DEFAULT 0, AssignedTo INT NOT NULL DEFAULT 0, AssignedBy INT NOT NULL DEFAULT 0, AssociationId INT NOT NULL DEFAULT 0, Priority NVARCHAR(20) NOT NULL DEFAULT 'medium', Status NVARCHAR(50) NOT NULL DEFAULT 'pending', DueDate DATETIME2 NOT NULL DEFAULT GETUTCDATE(), ProgressNote NVARCHAR(MAX) NULL, AttachmentUrls NVARCHAR(MAX) NULL, RequestStatus NVARCHAR(50) NULL, RequestedDueDate DATETIME2 NULL, RequestedDescription NVARCHAR(MAX) NULL, ReassignReason NVARCHAR(MAX) NULL, ReassignedFrom INT NULL, Duration NVARCHAR(50) NULL, CompletedAt DATETIME2 NULL, CreatedAt DATETIME2 NOT NULL DEFAULT GETUTCDATE());

IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME='ChatMessages')
    CREATE TABLE ChatMessages (Id INT PRIMARY KEY IDENTITY(1,1), SenderId INT NOT NULL DEFAULT 0, ReceiverId INT NULL, GroupId INT NULL, Message NVARCHAR(MAX) NOT NULL DEFAULT '', Type NVARCHAR(20) NOT NULL DEFAULT 'text', Payload NVARCHAR(MAX) NULL, IsRead BIT NOT NULL DEFAULT 0, CreatedAt DATETIME2 NOT NULL DEFAULT GETUTCDATE());

IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME='ChatGroups')
    CREATE TABLE ChatGroups (Id INT PRIMARY KEY IDENTITY(1,1), GroupName NVARCHAR(255) NOT NULL DEFAULT '', CreatedBy INT NOT NULL DEFAULT 0, AssociationId INT NOT NULL DEFAULT 0, CreatedAt DATETIME2 NOT NULL DEFAULT GETUTCDATE());

IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME='ChatGroupMembers')
    CREATE TABLE ChatGroupMembers (Id INT PRIMARY KEY IDENTITY(1,1), GroupId INT NOT NULL DEFAULT 0, UserId INT NOT NULL DEFAULT 0);

IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME='Clients')
    CREATE TABLE Clients (Id INT PRIMARY KEY IDENTITY(1,1), AssociationId INT NOT NULL DEFAULT 0, Name NVARCHAR(255) NOT NULL DEFAULT '', Company NVARCHAR(255) NOT NULL DEFAULT '', Email NVARCHAR(255) NOT NULL DEFAULT '', Phone NVARCHAR(20) NULL, LogoUrl NVARCHAR(500) NULL, IsActive BIT NOT NULL DEFAULT 1, IsDeleted BIT NOT NULL DEFAULT 1, CreatedAt DATETIME2 NOT NULL DEFAULT GETUTCDATE());

IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME='StaffTasks')
    CREATE TABLE StaffTasks (Id INT PRIMARY KEY IDENTITY(1,1), AssociationId INT NOT NULL DEFAULT 0, AssignedTo INT NOT NULL DEFAULT 0, AssignedBy INT NOT NULL DEFAULT 0, TaskName NVARCHAR(255) NOT NULL DEFAULT '', Description NVARCHAR(MAX) NULL, Priority NVARCHAR(20) NOT NULL DEFAULT 'medium', Status NVARCHAR(50) NOT NULL DEFAULT 'pending', IsRecurring BIT NOT NULL DEFAULT 0, RecurrenceType NVARCHAR(20) NULL, DueDate DATETIME2 NOT NULL DEFAULT GETUTCDATE(), CompletedAt DATETIME2 NULL, IsDeleted BIT NOT NULL DEFAULT 1, CreatedAt DATETIME2 NOT NULL DEFAULT GETUTCDATE());

IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME='Announcements')
    CREATE TABLE Announcements (Id INT PRIMARY KEY IDENTITY(1,1), CompanyId INT NOT NULL DEFAULT 0, Message NVARCHAR(MAX) NOT NULL DEFAULT '', StartAt DATETIME2 NOT NULL DEFAULT GETUTCDATE(), EndAt DATETIME2 NOT NULL DEFAULT GETUTCDATE(), IsActive BIT NOT NULL DEFAULT 1, IsDeleted BIT NOT NULL DEFAULT 1, CreatedAt DATETIME2 NOT NULL DEFAULT GETUTCDATE());

IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME='DailyReportDrafts')
    CREATE TABLE DailyReportDrafts (Id INT PRIMARY KEY IDENTITY(1,1), UserId INT NOT NULL DEFAULT 0, AssociationId INT NOT NULL DEFAULT 0, ReportDate DATETIME2 NOT NULL DEFAULT GETUTCDATE(), RowsJson NVARCHAR(MAX) NOT NULL DEFAULT '[]', IsSubmitted BIT NOT NULL DEFAULT 0, UpdatedAt DATETIME2 NOT NULL DEFAULT GETUTCDATE(), CreatedAt DATETIME2 NOT NULL DEFAULT GETUTCDATE());

IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME='AssistanceRequests')
    CREATE TABLE AssistanceRequests (Id INT PRIMARY KEY IDENTITY(1,1), UserId INT NOT NULL DEFAULT 0, AssociationId INT NOT NULL DEFAULT 0, Message NVARCHAR(MAX) NOT NULL DEFAULT '', IsRead BIT NOT NULL DEFAULT 0, CreatedAt DATETIME2 NOT NULL DEFAULT GETUTCDATE());

-- Fix IsDeleted=0 rows to be visible (IsDeleted=1 means active in this app)
UPDATE Properties SET IsDeleted = 1 WHERE IsDeleted = 0;
UPDATE Notifications SET IsDeleted = 1 WHERE IsDeleted = 0;
UPDATE Users SET IsDeleted = 1 WHERE IsDeleted = 0;
UPDATE Associations SET IsDeleted = 1 WHERE IsDeleted = 0;
UPDATE Clients SET IsDeleted = 1 WHERE IsDeleted = 0;
UPDATE StaffTasks SET IsDeleted = 1 WHERE IsDeleted = 0;
UPDATE Announcements SET IsDeleted = 1 WHERE IsDeleted = 0;
UPDATE Roles SET IsDeleted = 1 WHERE IsDeleted = 0;
